----请求全部礼包数据
function LxGuildGiftHandler:GuildGiftDataReq()
    local proto = LxProtoHelper.CreateProto(LxProtoIds.GuildGiftDataReq)
    SendMessage(LxProtoIds.GuildGiftDataReq, proto)
end

----领取礼包  id: 礼包id,0-领取全部       type: 礼包类型
function LxGuildGiftHandler:GuildGiftReceiveReq(id, type)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.GuildGiftReceiveReq)
    proto.id = id
    proto.type = type
    SendMessage(LxProtoIds.GuildGiftReceiveReq, proto)
end

----匿名选项
function LxGuildGiftHandler:GuildGiftAnonymousReq(anonymous)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.GuildGiftAnonymousReq)
    proto.anonymous = anonymous
    SendMessage(LxProtoIds.GuildGiftAnonymousReq, proto)
end

