--- s2c

----全部礼包数据下发
function LxGuildGiftHandler:OnGuildGiftDataResp(pb)
    ModuleCenter.GuildGift:SetGiftDataList(pb.gift)
    ModuleCenter.GuildGift:SetKeyCount(pb.keyCount)
    ModuleCenter.GuildGift:SetBoxGiftRefId(pb.keyBoxRefId)
    ModuleCenter.GuildGift:SetAnonymous(pb.anonymous)
    ModuleCenter.GuildGift:SetBattleGiftAlreadyGetCount(pb.type1Count)
    FireEvent(EventNames.GUILD_GIFT_INFO_UPDATE)
end

----领取礼包后返回的数据
function LxGuildGiftHandler:OnGuildGiftReceiveResp(pb)
    if pb.rewardInfo ~= nil then
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.GuildGift, pb.rewardInfo)
    end
    ModuleCenter.GuildGift:SetKeyCount(pb.keyCount)
    ModuleCenter.GuildGift:SetBattleGiftAlreadyGetCount(pb.type1Count)
    ModuleCenter.GuildGift:SetIsReceive(pb.type, pb.ids, pb.idRewardInfo)
    FireEvent(EventNames.GUILD_GIFT_INFO_UPDATE)
end

----匿名选项请求后返回的数据
function LxGuildGiftHandler:OnGuildGiftAnonymousResp(pb)
    ModuleCenter.GuildGift:SetAnonymous(pb.anonymous)
    FireEvent(EventNames.GUILD_GIFT_ANONYMOUS_UPDATE)
end

---礼包数据更新
function LxGuildGiftHandler:OnGuildGiftUpdateResp(pb)
    ModuleCenter.GuildGift:SetNotGetGiftNum(pb.num)
    self:GuildGiftDataReq()
end

return LxGuildGiftHandler